import { createHash } from "node:crypto";
import { mkdir, readFile, rm, writeFile } from "node:fs/promises";
import { tmpdir } from "node:os";
import { basename, dirname, extname, join, resolve } from "node:path";
import { fileURLToPath, pathToFileURL } from "node:url";

import * as esbuild from "esbuild";

import type { ComposeNode } from "../jsx-runtime.js";
import type { RenderFormat } from "./ffmpeg-transcode.js";
import { recordHtml, type RenderSize } from "./playwright-driver.js";

export type { RenderFormat } from "./ffmpeg-transcode.js";
export {
  ChromiumNotFoundError,
  resolveChromiumExecutable,
  captureFrameBuffers,
  recordHtml,
  frameCountFor,
  DEFAULT_FRAME_RATE,
  DEFAULT_DEVICE_SCALE_FACTOR,
} from "./playwright-driver.js";
export type { RenderedPack, RecordHtmlOptions } from "./playwright-driver.js";
export { concatMp4Segments } from "./concat.js";

export type RenderOptions = {
  out?: string;
  slug?: string;
  size?: RenderSize;
  formats?: RenderFormat[];
  durationMs?: number;
  fps?: number;
  deviceScaleFactor?: number;
};

export type RenderResult = {
  pack: {
    mp4?: string;
    webm?: string;
    poster?: string;
    gif?: string;
  };
  durationMs: number;
};

const DEFAULT_SIZE: RenderSize = { width: 1920, height: 1080 };
const DEFAULT_FORMATS: RenderFormat[] = ["mp4", "webm", "poster"];
const DEFAULT_DURATION_MS = 3000;
// 60s × 24fps = 1440 screenshots, ~50s of render wall-clock. Past this point
// the render is almost certainly a runaway value from a bad inferDurationMs
// match or a composition that should be split into multiple scenes.
const MAX_DURATION_MS = 60_000;

/**
 * Compile a `.compose.tsx` file to its final composition HTML — the exact path
 * render() uses (esbuild transform → dynamic import → compileToHtml → base-href).
 * Exposed so the frame-level gates (determinism, Phase 4 Scene) can render the
 * same composition without forking this pipeline.
 */
export async function compileCompositionFile(compositionPath: string): Promise<string> {
  const absolutePath = resolve(compositionPath);
  const node = await loadComposition(absolutePath);
  return addCompositionBaseHref(await compileRuntimeToHtml(node), absolutePath);
}

export async function render(
  compositionPath: string,
  options: RenderOptions = {},
): Promise<RenderResult> {
  const absolutePath = resolve(compositionPath);
  const slug = options.slug ?? basename(absolutePath, extname(absolutePath));
  const outBase = resolve(options.out ?? join(process.cwd(), slug));
  const formats = options.formats ?? DEFAULT_FORMATS;

  const html = await compileCompositionFile(absolutePath);
  // Explicit options.durationMs is trusted (user said so on the CLI).
  // An inferred duration is capped because data-duration-ms could be a
  // runaway value from a buggy primitive or a deliberate resource bomb.
  let durationMs: number;
  if (options.durationMs !== undefined) {
    durationMs = options.durationMs;
  } else {
    const inferred = inferDurationMs(html) ?? DEFAULT_DURATION_MS;
    if (inferred > MAX_DURATION_MS) {
      throw new Error(
        `Inferred composition duration ${inferred}ms exceeds ${MAX_DURATION_MS}ms cap. ` +
          `Fix data-duration-ms in the composition or pass --duration to render this on purpose.`,
      );
    }
    durationMs = inferred;
  }

  await mkdir(dirname(outBase), { recursive: true });
  const pack = await recordHtml({
    html,
    durationMs,
    size: options.size ?? DEFAULT_SIZE,
    formats,
    outBase,
    fps: options.fps,
    deviceScaleFactor: options.deviceScaleFactor,
  });

  return { pack, durationMs };
}

async function compileRuntimeToHtml(node: ComposeNode): Promise<string> {
  const runtime = (await import(
    pathToFileURL(resolveRuntimeEntry("index.mjs")).href
  )) as { compileToHtml: (node: ComposeNode) => string };
  return runtime.compileToHtml(node);
}

async function loadComposition(compositionPath: string): Promise<ComposeNode> {
  const source = await readFile(compositionPath, "utf8");
  const transformed = await esbuild.transform(source, {
    loader: "tsx",
    jsx: "automatic",
    jsxImportSource: "@reshot/compose",
    format: "esm",
    sourcemap: "inline",
    sourcefile: compositionPath,
  });

  const hash = createHash("sha256")
    .update(compositionPath)
    .update(source)
    .digest("hex")
    .slice(0, 16);
  const tempPath = join(tmpdir(), `compose-${hash}.mjs`);
  const code = rewriteComposeImports(transformed.code);

  try {
    await writeFile(tempPath, code, "utf8");
    const moduleUrl = `${pathToFileURL(tempPath).href}?t=${Date.now()}`;
    const mod = (await import(moduleUrl)) as { default?: unknown };
    const exported = mod.default;
    const node = typeof exported === "function" ? exported() : exported;
    if (!node) {
      throw new Error("Composition file must default-export a Composition function.");
    }
    return node as ComposeNode;
  } finally {
    await rm(tempPath, { force: true });
  }
}

function rewriteComposeImports(code: string): string {
  const replacements: Record<string, string> = {
    "@reshot/compose": pathToFileURL(resolveRuntimeEntry("index.mjs")).href,
    "@reshot/compose/jsx-runtime": pathToFileURL(
      resolveRuntimeEntry("jsx-runtime.mjs"),
    ).href,
    "@reshot/compose/jsx-dev-runtime": pathToFileURL(
      resolveRuntimeEntry("jsx-dev-runtime.mjs"),
    ).href,
  };

  let next = code;
  for (const [specifier, replacement] of Object.entries(replacements)) {
    next = next.replaceAll(`from "${specifier}"`, `from "${replacement}"`);
    next = next.replaceAll(`from '${specifier}'`, `from "${replacement}"`);
    next = next.replaceAll(`import("${specifier}")`, `import("${replacement}")`);
    next = next.replaceAll(`import('${specifier}')`, `import("${replacement}")`);
  }
  return next;
}

function resolveRuntimeEntry(fileName: string): string {
  const currentDir =
    typeof __dirname === "string"
      ? __dirname
      : dirname(fileURLToPath(import.meta.url));
  return join(currentDir, fileName);
}

function addCompositionBaseHref(html: string, compositionPath: string): string {
  const baseHref = pathToFileURL(`${dirname(compositionPath)}/`).href;
  return html.replace("<head>", `<head><base href="${baseHref}">`);
}

function inferDurationMs(html: string): number | undefined {
  const match = html.match(/data-duration-ms="(\d+(?:\.\d+)?)"/);
  if (!match) return undefined;
  const value = Number(match[1]);
  return Number.isFinite(value) ? value : undefined;
}
